var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"RAUL_SCAVENGER_NULL_NULL","text":{"KOREA":"이런, 왼쪽 다리가 또 맛이 가 버렸네.","JPN":"おっと、左足がまた壊れちまったみたいだな。","ENG":"Uh-oh, my left leg is acting up again.","TWN":"該死！左腳又不給力了！"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"RAUL_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"RAUL_SCAVENGER_NULL_NULL","text":{"KOREA":"서브스톰에 가는 대로 신품으로 다시 맞춰야겠어.","JPN":"サブストームに着いたら新品に取り替えないと。","ENG":"I'd better get a new one as soon as I'm back in Substorm.","TWN":"等回到次級風暴後又要買新的來換了！"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"RAUL_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"RAUL_SCAVENGER_NULL_NULL","text":{"KOREA":"깡통, 아까 여자애가 쏜 탄환 말이야. 두목이 머리 뺏길 때 당했던 거 맞지?","JPN":"ボロ缶、さっきの女の子が撃った弾丸なんだけど。ボスが頭部を奪われた時にやられたものと一緒だったよな？","ENG":"Tin Can, about the bullet that the girl fired at us. It's the same one that cost the Boss's head, isn't it?","TWN":"鐵桶，剛剛那個女生發射的彈藥，就是老大頭被搶走時打中的那個吧？"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"RAUL_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"ROJO_SCAVENGER_NULL_NULL","text":{"KOREA":"그래. 격발 시 흡수한 카운터의 CRF를 강력한 전자기 펄스로 변환하는 탄환이다.","JPN":"ああ。撃発時に吸収したカウンターのCRFを強力な電子パルスに変換する弾丸だ。","ENG":"Yes. It feeds on Counters' CRF and releases a powerful EMP when fired.","TWN":"沒錯，那個彈藥會在爆炸時，將吸收的制裁者CRF，轉換成強烈的電磁脈衝。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"ROJO_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"ROJO_SCAVENGER_NULL_NULL","text":{"KOREA":"그 때는 그걸 함대 규모의 포격으로 쏟아부었으니까.","JPN":"あの時は、それを艦隊規模の砲撃でぶち込んできたからな。","ENG":"At that time, the Coalition Fleet showered us with those bullets.","TWN":"而那時候那個彈藥是以艦隊規模在發射的，量之龐大。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"ROJO_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"COLLECTOR_NPC_NULL_NULL","text":{"KOREA":"알파트릭스 놈들이 직접 칼을 빼들었는데 잡담이 잘도 나오나 보군.","JPN":"アルファトリックスの連中が本腰を入れて来たのに、よくそんな呑気に雑談できるな。","ENG":"Alphatrix has stepped in, and you're chatting as if everything's just peachy.","TWN":"阿爾法崔克斯的人親自介入了，看來應該是有收到風聲。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"COLLECTOR_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"COLLECTOR_NPC_NULL_NULL","text":{"KOREA":"목적지까진 얼마나 남았지?","JPN":"目的地まではあとどれくらいだ？","ENG":"How far are we from our destination now?","TWN":"距離目的地還有多遠？"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"COLLECTOR_NPC_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"RAUL_SCAVENGER_NULL_NULL","text":{"KOREA":"목적지인 서브스톰까지 앞으로 약 30분.","JPN":"目的地のサブストームまで残り約30分。","ENG":"Thirty minutes left until Substorm.","TWN":"距離目的地次級風暴還有30分鐘左右。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"RAUL_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"RAUL_SCAVENGER_NULL_NULL","text":{"KOREA":"다이브 신호는 더 이상 안 잡혀. 포기한 모양인데?","JPN":"ダイブ信号はこれ以上確認されない。諦めたかもな？","ENG":"I'm not getting any more Dive signals. They must have given up.","TWN":"而且沒有再收到躍入訊號咧？是放棄了嗎？"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"RAUL_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"RAUL_SCAVENGER_NULL_NULL","text":{"KOREA":"……라고 말씀드리는 순간, 빌어먹을 다이브 신호 포착!","JPN":"……と言った瞬間、ちくしょう、ダイブ信号捕捉！","ENG":"... No! Dammit, we're getting new Dive signals!","TWN":"……就在這個瞬間，又收到該死的躍入訊號囉！"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"RAUL_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"COLLECTOR_NPC_NULL_NULL","text":{"KOREA":"끈질기군. 다이브 포인트는 어디지?","JPN":"しつこいな。ダイブポイントはどこだ？","ENG":"How persistent! Where's the Dive point?","TWN":"有夠纏人的！ 躍入點在哪裡？"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"COLLECTOR_NPC_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"RAUL_SCAVENGER_NULL_NULL","text":{"KOREA":"어, 그러니까 그게……","JPN":"あ、えーと、それが……","ENG":"Err, that's... Mm...","TWN":"嗯…就是在……"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"RAUL_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"RAUL_SCAVENGER_NULL_NULL","text":{"KOREA":"……머리 위?","JPN":"……頭の上？","ENG":"Above our heads?","TWN":"……頭上方？"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"RAUL_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"OPR_NPC_NULL_NULL","text":{"KOREA":"스캐빈저 함선 발견. 육안으로 보일 정도로 가깝습니다.","JPN":"スカベンジャー艦船発見。肉眼で見えるほど近いです。","ENG":"We've found the Scavenger ship. It's close enough to see with the naked eye.","TWN":"發現清道夫艦船，就在肉眼可見的距離內！"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"MATADOR_SHIP_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"OPR_NPC_NULL_NULL","text":{"KOREA":"실장님 말씀이 맞았군요. 침식파장이 가장 강한 곳에 숨어 있었어요.","JPN":"室長のおっしゃったとおりですね。侵食波長が最も強いところに隠れていました。","ENG":"Chief, you were right. They've been hiding where Corruption waves are at their strongest.","TWN":"室長說的沒錯！他們果然躲在侵蝕波最強的地方。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"MATADOR_SHIP_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"OPR_NPC_NULL_NULL","text":{"KOREA":"놈들은 이제 독 안에 든 쥐나 다름없습니다.","JPN":"やつらはもう袋のネズミ同然です。","ENG":"Now, they're just as good as dead.","TWN":"那傢伙現在與甕中之鱉無異！"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"MATADOR_SHIP_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};